INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_237512','Ой наступає та Чорна Хмара','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1958','1. Українські народні пісні у записах М. Лисенка. Комплект листівок. Художник А.Базилевич. - К.: Мистецтво, 1966','Ноти у джерелі 1 подані за: М.В.Лисенко. Зібрання творів у двадцяти томах. К.: Мистецтво, 1958 Ой наступає та Чорна Хмара став Дощ накрапать — Пісню зачинають Святоріздвяні та Щедровечірні образці. Воскресна. Застільна. Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. Ой Ми зіслані на признаванє. Байді Молодому Мед-горілку пити. Один бере за чуприну другий дуку б''є. Но ми докажем своїм Клинком. Листки з приводу цієї Пісні: Коляда і Великдень: Різдво і Відродження Світа. Українські реліґійні роздуми про Неволю та Спасіння Стежки до листків про Українські традиції.','Ой наступає та Чорна Хмара став Дощ накрапать
Ой там збиралась Бідна Голота до корчми гулять |(2)

Темна Хмара наступила став Дощик іти
Благослови Отамане намет нап''ясти              |(2)

Ой нап''яли Козаченьки червоний намет
Та й п''ють вони горілочку ще й Солодкий Мед    |(2)

Усі пани усі дуки у наметі сіли
Наша Браття Сіромашня та й не посміли          |(2)

Наша Браття Сіромашня та й не посміли
Взяли кварту горілки з жарту на Дощі сіли      |(2)

Прийшов же наш Отаман стало йому жаль
Над своєю головою жупан свій розп''яв           |(2)

Іде багач іде дукач вихваляється
Із нашої Голотоньки насміхається               |(2)

Із нашої Голотоньки насміхається:
За що ж тая Голотонька напивається?            |(2)

Ой як крикне Пан-Отаман на свою Силу
Візьміть-візьміть превража дуку вибийте в шию  |(2)

Один бере за чуприну другий дуку б''є
Не йди не йди превражий дуко де Голота п''є     |(2)

Пішов багач пішов дукач і не оглядався
Десятому заказував щоб не насміхався           |(2)','[''pisni.org.ua'', ''cat:kozacki'', ''cat:suspilno-politychni'', ''Козацькі пісні'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_237512'), datetime('now')),datetime('now'));
