INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2374616','В небі зірка нині засіяла','Музика: Олег Майовський Слова: Олег Майовський','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'В небі зірка
Нині засіяла,
То Марія Діва
Сина родила,
Ніжненько сповила,
В ясла вложила
Сина Божого!

В полі пасли
Пастухи отару,
Раптом заспівали
Хори в небесах
Пастушки побігли,
Щоб вклонитися
Сину Божому!

Того часу мудреці
Зі Сходу
Дитині вклонитись
Здалеку прийшли,
Коштовні дарунки
Йому принесли,
Сину Божому!

І ми нині разом
Заспіваймо,
Богу принесемо
Чистії серця,
Добрими ділами
Прославим Отця,
Сина Божого!
Сина Божого!','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:shchedrivky'', ''cat:suchasni-pisni-rizdvo'', ''Колядки'', ''Щедрівки'', ''Сучасні пісні про Різдвяні свята'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2374616'), datetime('now')),datetime('now'));
