INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_237251','Ой до Нори Мишко до Нори','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Пісня-Гра. Забави з Паруванням-Цілуванням. Гаїлки-Великдень: Українське свято Відродження Світа. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Втікай Мишко до Нори Золотої Комори. Листки з приводу цієї Пісні: Коляда і Великдень: Різдво і Відродження Світа. Про Українські назви місяців Марець і Май. Стежки до листків про Українські традиції.','Ой до Нори Мишко до Нори
Та до Золотої Комори
Чорний Коточок Мишку не зловить
Мишка в Дірку Золоту Комірку
До Нори до Нори!','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_237251'), datetime('now')),datetime('now'));
