INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2375165','Ой, там наді Львовом чорна хмара наступає',NULL,'uk','ukr_ssr_1919_1991',NULL,NULL,'аудіозапис','Місце побутування: с. Лопушанка, Хащівська сільрада, Турківський район, Львівська область. Респонденти: Кметик Степанія Степанівна, Боберська Марія Степанівна, Волошинівська Настя Федорівна. Збирачі: Артем''як Мар''яна, Довгань Оксана, Папіш Марія.','Ой, там наді Львовом
Чорна хмара наступає,
Там двох синів - українців |
Страшна судьба чекає.      | (2)

Один був українець,
Це був Білас Василь,
Боровся за Україну,        |
Хоч був ще молодий.        | (2)

Другий був українець,
Це був Білас Василь,
Боровся за Україну,        |
Хоч був ще молодий.        | (2)

Боролися соколи,
Боролися оба,
Бо хтіли визволити         |
Вкраїну із ярма.           | (2)','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2375165'), datetime('now')),datetime('now'));
