INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2374010','Розпрощався козак із своєю ріднею','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1961','аудіозапис','Місце побутування: с. Жукотин, Лімнянська сільрада, Турківський район, Львівська область. Респондент: Мацур Марія Степанівна, 1961 р.н. Збирачі: Іванищук Марія, Беднарська Ружена.','Розпрощався козак із своєю ріднею,
Вибирався в далеку дорогу.
За свій рідний край,
За стрілецький звичай,
Підем в бій за свою перемогу!

От вітер колише шовкову траву,
Молодий дуб додолу схилився,
Листям шелестить, вбитий козак лежить,
Над ним коник його зажурився...

Ой, коню ж мій, коню, не стій наді мною,
Я тим часом полежу прикритий.
Лети ж, коню мій, скажи ненці рідній,
Що я лежу у полі убитий.

Нехай ненька і батько, і сестри, і брати,
Нехай вони за мною не плачуть,
Я в степу лежу, за ріднею тужу,
Чорний ворон наді мной закряче.

Висиплють на мені високу могилу
І посадять червону калину,
Калина цвіте, а дівчина плаче:
Ой, устань же, молодий козаче.

Ряди за рядами ідуть партизани,
До походу гармати їм грають.
На славу і честь, і березовий хрест,
Дрібні сльози на грудь випадають.','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2374010'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2374010','Розпрощався козак із своєю ріднею','Розпрощався козак із своєю ріднею,
