INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_237369','Тай нема в світі Правди не зіскати','Українська народна пісня. Виконує: Михайло Хай','uk','ukraine_before_1917',NULL,NULL,'Українські релігійні роздуми про Спасіння © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2003','Отець-Рідна-Мати — У Піснях символ Господа Бога і звертання до Нього. Також символ Сім''ї як Святости та присутности Бога (Давня Правдонька Старих Людей). Можлива гра слів: Отець-Рідня-Мати. Спасительна: світ не по Правді. Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. Ой Ми зіслані на признаванє. Нема в світі Правди не зіскати. А вже ж тая Свята Правда стоїть у Порога. Листки з приводу цієї Пісні: Еротичні містерії, тиждень від Катерини 7.12 до Калети. Доля. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Стежки до листків про Українські традиції.','Тай нема в світі Правди Правди не зіськати
Скільки в світі тії Правди що Отець-да-Ма...(ти)

То вже ж тую Святу Правду під нозі пускають
А злую ж ту неправду медом-вином напувають

А вже ж тая Свята Правда стоїть у порога
А злая ж та неправда сидить конець столу

А вже ж тая Свята Правда сидить у темниці
А злая ж та неправда с панами в світли...(ці)

А вже ж тая Свята Правда Правда вже померла
А злая ж та неправда увесь світ зажерла

Тай нема в світі Правди Правди не зіськати
Доки ж та неправда буде правдовати |(2)','[''pisni.org.ua'', ''cat:dumy'', ''cat:suspilno-politychni'', ''Думи'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_237369'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_237369','Тай нема в світі Правди не зіскати','Тай нема в світі Правди Правди не зіськати
