INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2375212','Світит місяць між горами',NULL,'uk','ukr_ssr_1919_1991',NULL,NULL,'аудіозапис','Місце побутування: с. Жукотин, Лімнянська сільрада, Турківський район, Львівська область. Респонденти: Пенц Настя Луківна, Лихновська (Мацур) Леся Іванівна, Голотяк (Мушак) Ганна Федорівна. Збирачі: Винницька Ліля, Кльок Юлія.','Світит місяць між горами,
Потискают нас ґайдани!

Ви, ґайдани, попукайте,
Україні волю дайте!

Встань, Тарасе,
Встань, Богдане,
Українські всі гетьмани!

Встань, Тарасе, пробудися,
На свій нарід подивися!

Як твій нарід тут бідує,
Та й по тюрмах голодує!

Ворог робит, шо він хоче,
Винимає людям очи!

Ой, ви, хлопці молодії,
Куйте зброї стальовії!

Бо та зброя стальовая -
Для ворога вна страшная!

Станьте, хлопці,
В чистім полю,
Україні дайте волю!

Україна - наша мати,
Як не встане - мус вмирати!','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2375212'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2375212','Світит місяць між горами','Світит місяць між горами,
Потискают нас ґайдани!

Ви, ґайдани, попукайте,
Україні волю дайте!

Встань, Тарасе,
Встань, Богдане,
Українські всі гетьмани!

Встань, Тарасе, пробудися,
На свій нарід подивися!

Як твій нарід тут бідує,
Та й по тюрмах голодує!

Ворог робит, шо він хоче,
Винимає людям очи!

Ой, ви, хлопці молодії,
Куйте зброї стальовії!

Бо та зброя стальовая -
Для ворога вна страшная!

Станьте, хлопці,
