INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_237498','У Київі на Риночку музики заграла','Українська народна пісня. Виконує: Марія Казимирів','uk','ukraine_before_1917',NULL,NULL,'Українська Епічна Традиція. Кружало. Проект „Моя Україна – Берви“. 2003 Арт-Екзистенція, УЕЛФ, Арт Велес.','Пара Байді — Бондарівна:-) Воскресна: світ не по Правді. Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. Там гуляла Бондарівна як Пишная Пава. Там Молода Бондарівна пила тай гуляла. Листки з приводу цієї Пісні: Коляда і Великдень: Різдво і Відродження Світа. Українські реліґійні роздуми про Неволю та Спасіння Еротичні містерії, тиждень від Катерини 7.12 до Калети. Доля. Стежки до листків про Українські традиції.','У Київі на Риночку музики заграла
Там Молода Бондарівна пила тай гуляла    |(2)

А як прийшов пан Канявський тай у перший танець
Тай зажартував до неї буду твій коханець   |(2)

А Молода Бондарівна звичаю не знала
Відвирнула білу ручку тай вдарила пана     |(2)

Утікала Бондарівна Темними Лісами
За нев гнало два жовніри бистрими конями   |(2)

Догонили Бондарівну привели до пана
Вийди-вийди пан Канявський поглянь на Коханку  |(2)

А як вийшов пан Канявський із своєй світлиці
Потискає Бондарівну за біленькі лиці       |(2)

Ой чи хочеш Бондарівно Мід-горілку пити
Ой чи хочеш Бондарівно в сирій землі гнити |(2)

Ой не хочу пан Канявський Мід-горілку пити
Тільки хочу пан Канявський в серій земли гнити |(2)','[''pisni.org.ua'', ''cat:dumy'', ''cat:kozacki'', ''Думи'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_237498'), datetime('now')),datetime('now'));
