INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2375226','Світить місяць, світить ясний',NULL,'uk','ukr_ssr_1919_1991',NULL,NULL,'аудіозапис','Місце побутування: смт Запитів, Кам''янка-Бузький район, Львівська область. Респондент: Максимишин Марія Олексіївна. Збирачі: Вовчак Андрій, Мартиник Соломія.','Світить місяць, світить ясний,
Світить ясних дві зорі,
А ми мучимось у лісі -
Самі хлопці молоді.

Сон приснився там дивненький,
Що я вдома ночував.
Пробудився, а я в лісі -
Став і гірко заплакав.

Україно, Україно!
Ти купаєшся в крові,
А ми мучимось по тюрмах -
Самі хлопці молоді.

Україно, моя нене,
Твоя доля вже така -
Виганяє москаль з хати
Молодого юнака.

Виганяє, виганяє,
Та вже довго ни буде,
Наша славна Україна
Самостійною буде!','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2375226'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2375226','Світить місяць, світить ясний','Світить місяць, світить ясний,
