INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2375318','У полоні, в неволі була ти',NULL,'uk','ukr_ssr_1919_1991',NULL,NULL,'аудіозапис','Місце побутування: смт Запитів, Кам''янка-Бузький район, Львівська область. Респондент: Максимишин Марія. Збирачі: Вовчак Андрій, Мартиник Соломія.','У полоні, в неволі була ти,
