INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_237573','Ой да у Святую Неділеньку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Українські релігійні роздуми про Спасіння © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2003','Про яку неволю мова, про яке бидло-невольників? Що за каторга і куди вона пливе? Чому плач? "Ой да у Святую Неділеньку барзе рано пораненьку" — Свята Неділя: містичний день Воскресіння, Відродження Світа. "У тяжкій турецькій неволі заплакали" — Тут "турецька неволя" — загальний символ будь-якої неволі, тілесної чи духовної, та примусу чужого звичаю. Порівняти Плач Невольників з Плачем Сокола або Господа в Колядках: Господь плаче прийшовши між нарід і з його сліз творяться животворні води. Ім''я Господа буває в Колядках синонімом Христа, Спасителя Світа, що визволяє людей від вічної недолі. "Подай-подай нам Господи з неба дрібен дощик" — Дрібен Дощик: Колядний символ Бога в Астральній Трійці: Дрібний Дощик, Місяць і Зоря. Тут символ Світу Правди і приходу Господа, оновлення, воскресіння, визволення з примусу неправди і чужого. Порівняти з тихим вітриком, старозавітним символом Бога. Спасительна: світ не по Правді. Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. Ой Ми зіслані на признаванє. Нема в світі Правди не зіскати. У Чистому Степу собі Живности доставати. Господа Милосердного прохали та благали. Бо вже ж нам сяя Турецькая Каторга надоїла. А вже років двісті як Козак в неволі А вже років двісті як Козак у неволі А вже років триста як Козак в неволі Вже більше літ двісті як Козак в неволі Всі покою щиро прагнуть Дарувала Катерина Козакам лимани Де Дніпро наш котить хвилі За Сибіром Сонце сходить Хлопці не зівайте Зібралися всі Бурлаки до рідної xати Зібралися всі бурлаки до рідної xати (2) Зібралися всі бурлаки (Чорнобильська) Ми по таборах і тюрмах карались до загину Ой да у Святую Неділеньку Ой зза Гори зза Лиману Вітер повіває Ой пише-пише да Гетьман Мазепа до Палія листи Ой піду я Лугом Лугом-Долиною Спіте діти спіте любі спіть не просинайтесь У Глуxові в городі во всі дзвони дзвонять Уже років з двісті як Козак в неволі Заплакала Україна така її Доля. Повели ж Його Морозенка на Савур-могилу. За тобою Морозенко вся Вкраїна плаче. І усіх вас Невольників із Темниці випускати. І самого ж мене у Чорнеє Море іспустіть. Листки з приводу цієї Пісні: Українські реліґійні роздуми про Неволю та Спасіння Еротичні містерії, тиждень від Катерини 7.12 до Калети. Доля. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Стежки до листків про Українські традиції.','Гей-гей-гей-гей
Ой да у Святую Неділеньку
Барзе рано пораненьку
Ой да тож то не Сизії Орли заклекотали
Як то біднії невольники
У тяжкій турецькій неволі заплакали
Угору руки підіймали кайданими забряжчали
Господа Милосердного прохали та благали
Гей

Гей подай-подай нам Господи
З неба дрібен дощик  а знизу та буйний вітер
Ой та чи не встала би та на Чорному Морі  бистрая хвиля
Ой та чи не позривала б вона якорів з турецької каторги
Гей-гей
Бо вже ж нам сяя турецькая каторга надоїла
Кайдани залізо ноги повривало
Білеє тіло козацькеє молодецькеє
Аж до самої кості пошмугляло
Гей-гей

Отож то баша турецький бусурманський
Недовірок християнський
Ой да тож то він на чердаки ісходжає
Да сам то теє добре зачуває
Да на свої слуги турки-яниченьки зозла гукає
Гей

Гей кажу-кажу я вам турки-яниченьки
Та добре ви дбайте барзе гадайте
По три пучки тернини по чотири червоної таволги
В руку набирайте з ряду з ряду заходжайте
Бидла невольника по тричі в однім місті затинайте
Гей-гей

Ой да тож то тії слуги турки-яниченьки
Ой да тож то вони добре дбали барзе гадали
По три пучки тернини по чотири червоної таволги
В руки набирали з ряду з ряду заходжали
Бідного невольника по тричі в однім місті затинали
Гей-гей
Ой як стали козаки-молодці
Ой як стали на собі кров християнську забачати
То стали землю турецькую
Віру прокляту бусурманськую
Клясти проклинати
Гей
Гей ти земле-земле турецькая
Віро проклята бусурманськая
Розлуко ти християнськая
Ой та не одного ж ти розлучила
А чи брата з сестрою а чи мужа з вірною жоною
А чи вірненького товариша з товаришем
Гей

Гей земле-земле десь справді ти єсть проклятая
Тільки турчину-кальянинину
на срібло на злато вельми багатая
Гей

Ой визволь нас визволь нас Господи
Всіх бідних невольників з тяжкої турецької неволі
На тихії води на яснії зорі у край веселий
Промежду народ хрещений в городи християнськії
До Отця-до-Неньки  до Родини сердешної
І на многії літа і до кінця віку
Гей-гей

Ой наперед уклоняюся Господу Богу
І отаману батькові кошовому
І всьому товариству кревному й сердечному
І всім головам слухающим
На многія літа до конця віка    Заспів (mp3)','[''pisni.org.ua'', ''cat:dumy'', ''cat:kozacki'', ''Думи'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_237573'), datetime('now')),datetime('now'));
