INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2375292','У Боберці на границі',NULL,'uk','ukr_ssr_1919_1991',NULL,NULL,'аудіозапис','Місце побутування: с. Лімна, Лімнянська сільрада, Турківський район, Львівська область. Респонденти: Голотяк Марія Іванівна, Бахур Параска Миколаївна, Мацур Стефанія Іванівна. Збирачі: Папіш Марія, Артем''як Мар''яна, Довгань Оксана, Слівка Маґдалена.','У Боберці на границі
Хатина стояла,
Там, де наших славних      |
Стрільців могила чекала.   | (2)

Вийшли хлопці з лісу,
Всюди було тихо.
Вни ни знали, що в ті хаті |
Чекає їх лихо.             | (2)

Соловей стояв на стрільці,
Решта було в хаті,
Аж тут соловей приходить,  |
Дає друзям знати.          | (2)

Аж тут Соловей підходить,
Дає друзям знати,
Що москалі на границі      |
Окружають хати.            | (2)

Хлопці кріса похапали,
Почали стріляти,
А москалі з кулеметів      |
Почали стріляти.           | (2)

Хлопці сильно утікали
Та й не боронились,
Гострі кулі засвистали,    |
Стрільці повалились.       | (2)

Двох ранили, двох убили,
Одного їмили,
Назад ручки му зв''язали,   |
Тяжко його били.           | (2)','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2375292'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2375292','У Боберці на границі','У Боберці на границі
Хатина стояла,
Там, де наших славних      |
Стрільців могила чекала.   | (2)

Вийшли хлопці з лісу,
Всюди було тихо.
Вни ни знали, що в ті хаті |
Чекає їх лихо.             | (2)

Соловей стояв на стрільці,
Решта було в хаті,
Аж тут соловей приходить,  |
Дає друзям знати.          | (2)

Аж тут Соловей підходить,
Дає друзям знати,
Що москалі на границі      |
Окружають хати.            | (2)

Хлопці кріса похапали,
Почали стріляти,
А москалі з кулеметів      |
Почали стріляти.           | (2)

Хлопці сильно утікали
Та й не боронились,
Гострі кулі засвистали,    |
Стрільці повалились.       | (2)

Двох ранили, двох убили,
Одного їмили,
Назад ручки му зв''язали,   |
Тяжко його били.           | (2)');
