INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2375354','Як геройство воювало',NULL,'uk','ukr_ssr_1919_1991',NULL,NULL,'аудіозапис','Місце побутування: с. Боберка, Боберківська сільрада, Турківський район, Львівська область. Респонденти: Бутрій Надія, Біжик Надія, Пиріг Надія. Збирачі: Артем''як Мар''яна, Папіш Марія, Довгань Оксана.','Як геройство воювало,
За свободу життя дало.

Дало життя за свободу,
За самостійність народу.

Подивіться, соколята,
Чи не несе Тиса тата?

Чи не несе Тиса тата,
Жінці - мужа, сестрі - брата?','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2375354'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2375354','Як геройство воювало','Як геройство воювало,
