INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_237818','Там за Лісом за Лугом ходить Козак за Плугом','Музика: народна Слова: Осип Маковей. Виконує: Ніна Матвієнко, Тріо "Золоті Ключі"','uk','ukraine_before_1917',NULL,NULL,'Українські релігійні роздуми про Спасіння © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2003','Спасительна: світ не по Правді. Українські релігійні роздуми про Воскресіння, і Спасіння. Ой Ми зіслані на признаванє. Нема в світі Правди не зіскати. Ой устань же Козаченьку. Оре Ниву не свою добре що в Своїм Краю. Хто посіє і пожне як не стане вже мене. За це Поле за Село їх не мало полягло. Листки з приводу цієї Пісні: Українські реліґійні роздуми про Неволю та Спасіння Коляда і Великдень: Різдво і Відродження Світа. Еротичні містерії, тиждень від Катерини 7.12 до Калети. Доля. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Стежки до листків про Українські традиції.','Там за Лісом за Лугом ходить Козак за Плугом
Оре Ниву не свою добре що в Своїм Краю       | (2)

Оре-оре тай туже хто Родині послуже
Хто посіє і пожне як не стане вже мене       | (2)

Станьте Коні Вороні бо Могили в загоні
Ще й до того на Межі і на лихо не чужі       | (2)

Тут Гармати орали Наші Хлопці вмирали
За це Поле за Село їх не мало полягло        | (2)

Тут пшениця поросте, синій блават зацвіте.
Козак сяде і спічне, бідні душі пом''яне...   | (2)

Там за Лісом за Лугом ходить Козак за Плугом
Десь далеко Громи б''ють людям жити не дають  | (2)','[''pisni.org.ua'', ''cat:suspilno-politychni'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_237818'), datetime('now')),datetime('now'));
