INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_237899','Яка ж ти гарна, Україно!','Музика: Євген Шантир Слова: Євген Шантир. Виконує: Євген Шантир','uk','ukraine_1991',NULL,NULL,NULL,'Збірка пісень "КОРАБЛИК"','ЯКА Ж ТИ ГАРНА, УКРАЇНО!
Вітри твої, Вкраїно, вільні,
Гуляють в горах і в лісах,
Степами і морями линуть
І скрізь тебе вітають так:
Приспів:
Яка ж ти гарна, Україно,
Як перша в юності весна,
В козацькій славі своїй долі
Вінок кохання ти сплела.
Дніпро твій сивий і могутній,
Ріка натхнення у віках,
Горами хвилі підіймає,
Дніпро реве та стогне так: (приспів)
Сини твої - завзяті хлопці
В човнах, на суші, в літаках,
В епохи різні історичні
Вони тобі співають так: (приспів)
Дочки твої - красуні милі,
Вони і в праці, і в піснях
Відомі в світі берегині,
Які тобі співають так: (приспів)
В віршах Шевченківських крилатих,
В жовто-блакитних прапорах,
В промовах Гетьманів Великих
Звучиш ти, Україно, так: (приспів)','[''pisni.org.ua'', ''cat:bardivski'', ''cat:himny-marshi'', ''cat:philosophic'', ''cat:suspilno-politychni'', ''cat:zahalni-cinnosti'', ''Бардівські пісні'', ''Гимни та марші'', ''Філософські пісні'', ''Суспільно-політичні пісні'', ''Пісні про загальнолюдські цінності'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_237899'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_237899','Яка ж ти гарна, Україно!','ЯКА Ж ТИ ГАРНА, УКРАЇНО!
