INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2375990','Гімн Народного Руху','Музика: Віктор Сушко Слова: Дмитро Павличко. Виконує: Етнографічний хор Гомін','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'В тюрмі, де мучились народи,
Зростав наш непокірний дух.
З неволі на шляхи свободи   |
На ясні зорі, тихі води     |
Покликав нас Народний Рух!  | (2)

Приспів:
В тяжку добу, в тяжку годину,
Як нам зламати хочуть спину,
Стає міцнішим во сто крат
Рух за народ, за Україну,
За Україну, за народ!

Лиш в єдності снага спасенна,
Так знов живий ланцюг твори!
Ставай рамено до рамена     |
Під наші рухівські знамена, |
Під синьо-жовті прапори!    | (2)

Приспів.

Ми наших предків кров і славу
Не згубимо в золі епох!
Ми справедливу й нелукаву,  |
Як храм, збудуємо державу,  |
Де правитиме правда й Бог!  | (2)

Приспів.','[''pisni.org.ua'', ''cat:himny-marshi'', ''Гимни та марші'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2375990'), datetime('now')),datetime('now'));
