INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2378697','Бік пробитий','Бік пробитий,
Нам відкритий струмінь спасіння,
Кров тече, тече вода −
Ціна іскупління.
Хрещення і Євхаристія −
Ось тайни нового життя,
Це Пасха Божого Христа,
Тож всі прийдіть до джерела!
