INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2381515','Моїм друзям','Музика: Дмитро Хома Слова: Дмитро Хома','uk','ukraine_1991',NULL,NULL,'авторське подання','Пісню виконує дует Горислава (Анна Мудра та Людмила Близнюк).','Я не чекаю вже давно
А ні дарунків, а ні слави.
Хочу посіяти зерно
На наші спільні добрі справи.
У цій життєвій метушні,
Коли я в радості чи в тузі,
Подарував Господь мені
Моїх найкращих в світі друзів!

Приспів:
Сьогодні дякую я музі -
Вам дорогі і щирі друзі
За те, що ви зі мною поруч!
Я з вами все переживу!
За наші зустрічі і мрії,
За ту любов, що душу гріє!
З Вами сумую і радію!
За те, що з вами я Живу!
І З Вами разом я Живу!

Життєва істина проста:
В час лихоліття і негоди,
Коли на всіх одна мета
Усі здолаєм перешкоди!
За нашу дружбу на віки,
Я повний келих підіймаю!
Із нетерпінням залюбки
Нової зустрічі чекаю!

Приспів.    Дует "Горислава" Анна Мудра і Людмила Близнюк','[''pisni.org.ua'', ''cat:druzhba'', ''Пісні про дружбу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2381515'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2381515','Моїм друзям','Я не чекаю вже давно
