INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2379818','Мій буквар, мій друг надійний!','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Мій буквар, мій друг надійний,
Прощавай ти назавжди,
У новий цей світ великий,
Двері ти усі відкрив!

Приспів:
Прощавай, букварик наш,
Дякує тобі весь клас!
Прощавай, букварик наш,
Дякує тобі весь клас!

Букви вчили ми завзято,
Ти нам всім допомогав,
І до світу знань доріжку
Наш букварик показав!

Приспів.

Сторінки усі гортали,
Та настав гортання час,
Не забудемо ніколи,
Як навчав букварик нас!

Приспів.','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2379818'), datetime('now')),datetime('now'));
