INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2379420','Заробітчани','Слова: Василь Чопей','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Хтось чекає чарівну весну,
Ми в тривозі, немов небезпека....
І в цю пору вже нам не до сну,
Бо дорога чекає далека...

Приспів:
Чужина, чужина, чужина...
Ми до неї уже, мов до дому,
Наче рідною стала вона,
Аж не віриться, навіть, самому...
Чужина, чужина, чужина...
Скільки там ще мені працювати?..
На волоссі уже сивина -
Рідні діти не можуть впізнати...

В небесах чути крик журавля,
Він у рідні краї прилітає...
Ну, а нас, нас чужа жде земля,
На своїй нам роботи немає...

Приспів.

І все це, і все це не з проста,
Не гадалка це нам нагадала...
На чужину ця влада пуста
Українців у найми послала...

Приспів.','[''pisni.org.ua'', ''cat:emigration'', ''Пісні про еміґрацію'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2379420'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2379420','Заробітчани','Хтось чекає чарівну весну,
Ми в тривозі, немов небезпека....
І в цю пору вже нам не до сну,
Бо дорога чекає далека...

Приспів:
Чужина, чужина, чужина...
Ми до неї уже, мов до дому,
Наче рідною стала вона,
Аж не віриться, навіть, самому...
Чужина, чужина, чужина...
Скільки там ще мені працювати?..
На волоссі уже сивина -
Рідні діти не можуть впізнати...

В небесах чути крик журавля,
Він у рідні краї прилітає...
Ну, а нас, нас чужа жде земля,
На своїй нам роботи немає...

Приспів.

І все це, і все це не з проста,
Не гадалка це нам нагадала...
На чужину ця влада пуста
Українців у найми послала...

Приспів.');
