INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2382124','У суботу на роботу','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'У суботу на роботу
Голова боліла,
У неділю на весілля
Мало-м не злетіла.

У сусіди весіллечко,
Пусти мене, нене,
Бо мій хлопець не танцює,
Чекає на мене.

У суботу на роботу
Та хай іде мама,
У неділю на весілля
Я вже піду сама.

У суботу на роботу
Піде мама з татом,
У неділю на весілля
То піду я з братом.

Іди, доню, до церковці
Усі дзвони дзвонять.
Ой, не піду, мамко моя,
Бо ніжки мня болять.

Іди, доню, на весілля
Як музика грає.
Дайте, мамко, черевички,
Я пошкандибаю.','[''pisni.org.ua'', ''cat:kolomyyky'', ''Коломийки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2382124'), datetime('now')),datetime('now'));
