INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2382111','Ой, що ти си, дівчинонько, гадала?','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, що ти си, дівчинонько,
Гадала, гадала,
Як зелена полонинка
Палала, палала?

Я гадала полонинку
Гасити, гасити,
Та не могла з-під явора
Води наносити.

Летів пташок понад верхи,
А я ся дивила,
Ой, який то пташок файний,
Коби-м ся імила.','[''pisni.org.ua'', ''cat:kolomyyky'', ''Коломийки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2382111'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2382111','Ой, що ти си, дівчинонько, гадала?','Ой, що ти си, дівчинонько,
