INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2382251','Ой, по вашій, кумцьо','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, по вашій, кумцьо,
Стрісі лазили качата,
Дай вам, Боже, молодята,
До року близнята.

