INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2382216','Ой, кувала зозуленька на високі брамі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, кувала зозуленька
На високі брамі,
Файно тобі було
При ріднийкі мамі.

Ой, жаль мені того
Сиру і тої сметани,
Що тя ненька годувала
Для чужої мами.

Ой, дружбо мій дорогийкий,
Тепер не спішися,
Як-ісь іще не напився,
То тепер й не дрися.

Не встидайся, дівчинонько,
Бо то нич не стидно,
Я на тебе ся подивлю,
А по тобі видно.

Ой, кувала зозуленька
В гаї зелененькім,
Сидить дівка за столом
В вельоні біленькім.

Не дивися, дівчинонько,
Що муж чорнобривий,
Бо ще не раз будеш спати
Під плотом, в жаливі.

Ой, як підеш за невістку
До мами чужої,
То прошу тя, дівчинонько,
Не забувай й свої.','[''pisni.org.ua'', ''cat:kolomyyky'', ''Коломийки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2382216'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2382216','Ой, кувала зозуленька на високі брамі','Ой, кувала зозуленька
