INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2382665','Ой, де ідеш, пане-брате?','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой де ідеш, пане-брате?
Чи на косовицю?
А на кого зіставляєш
Свою молодицю?

А на тебе зіставляю,
Мій брате Степане,
Доглядай ми молодиці,
З ким вона зістане.

Доглядай ми молодиці,
Доглядай ми жінки,
Як приїду з косовиці,
Куплю ти горілки!','[''pisni.org.ua'', ''cat:kolomyyky'', ''Коломийки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2382665'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2382665','Ой, де ідеш, пане-брате?','Ой де ідеш, пане-брате?
Чи на косовицю?
А на кого зіставляєш
Свою молодицю?

А на тебе зіставляю,
