INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_238395','Предвічний родився','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Предвічний родився від Діви,
Щоб люди світ його узріли.
Він із тьми нас виведе
І до світла приведе
Заблуканих.   |(2)

Новий рік ось Він зачинає
Новий Цар на престіл вступає.
Убогий к нам загостив,
Багатого засмутив
Ірода.        |(2)

Як Діва Сина породила,
Поганська віра утупила.
Пізнай Бога, храмино,
Веселися, дружино.
Христова!     |(2)

Привикай, Діво, повивати!
Не забудь, старче пильнувати!
Сотворителя свого
Знають Бога нашого
Звірята.      |(2)

Небесна луна освітила,
Як Діва Сина породила.
Цілу ніченьку світить,
Його воленьку творить,
Мусила.       |(2)

А звізди послухали царі,
Спішили, щоб принести дари:
Привітали пастирі,
А від так прийшли царі
До Царя.      |(2)

А Ірод з того засмутився,
Що Христос-Господь народився,
Казав Його шукати,
По всій землі питати,
Для зради.    |(2)

Іроду неуподобімся,
Вірні Христу поклонімося,
Щоб від гріхів заховав
На віки.      |(2)','[''pisni.org.ua'', ''cat:cerkovni'', ''Церковні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_238395'), datetime('now')),datetime('now'));
