INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_238267','Ось та Зірка!','Музика: Євген Шантир Слова: Євген Шантир. Виконує: Євген Шантир','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Я сьогодні з вами, парубки,
Йду на зустріч долі залюбки,
І до гурту хвацькі підійду,
І відверто ось таке скажу:
Приспів:
Ось і пісня, ось і танці, ось і я,
Ось та дівчина, що гарна, як весна,
І хай швидше закрутилася Земля,
Ось та Зірка, що тепер буде моя!
Ой, дівчата ж навкруги стрункі,
Ви дотепно підморгніть мені,
Бо кипить моя козацька кров, -
Серед вас є і моя любов!
Приспів.
Хай буває линуть журавлі,
На душі ж співають солов''ї,
Бо кохання є моє в житті,
З ним лунають ці слова прості!
Приспів.','[''pisni.org.ua'', ''cat:kozacki'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_238267'), datetime('now')),datetime('now'));
