INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2382726','Не там щастя, де багаті люди','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Не там щастя, не там доля,
Де багаті люди, —
Хто побрався по любові,
Тому добре буде.

За доброго чоловіка,
За доброго мужа
Цвіте жінка, як калина,
Чоловік — як ружа.

Ой, у мене чоловік,
Хай ніхто не гудить:
Встає рано до роботи,
А мене не будить.

Ой, миленький рано встає,
Милу прикриває:
Спи, миленька, до обіду,
Най ся вигріває.

Спи, миленька, до полудня,
Буду без обіду,
Щоби ладно виглядала,
Як з тобою піду.

Ой, кувала зозулиця
В лісі на горісі,
Буду жону пестувати,
Як ластівку в стрісі.

А меш її пестувати,
Не меш її гнати,
Бо вна тобі не служниця —
Твоїм дітям мати.

Жінка моя молоденька,
Медова, медова,
Як я тебе день не виджу,
Болить мя голова.

Вечір близько, сонце низько,
Чей додому зайду,
Чей я свою білявочку
Здоровеньку найду?

Коби моя білявочка
Здорова, здорова,
То би була вечерочка
Готова, готова!

Дякую тобі, миленький,
За ото красненько,
Що мі пішли із тобою
Літа веселенько.','[''pisni.org.ua'', ''cat:kolomyyky'', ''Коломийки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2382726'), datetime('now')),datetime('now'));
