INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2386869','Наша пані невелика','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Наша пані невелика,
У червоних черевиках
Вийшла та й жати —
Вечеряти йдуть...

Та винесла три скрипочки,
А четвертий - бас.
Всім дівочкам по скрипочці,
А сироті - бас.
Всі дівочки в скоки-боки,
А сирота в плач...

Наша пані різва,
Сім день на піч лізла.
І сміх, і біда —
Пані молода...','[''pisni.org.ua'', ''cat:obzhynkovi'', ''Обжинкові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2386869'), datetime('now')),datetime('now'));
