INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2385420','А зима сипле сніг лапатий','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'А зима сипле сніг лапатий,
А зима сипле сніг лапатий
Вітровій!..
Дід Мороз, поспішай на свято!
Дід Мороз, поспішай на свято -
Рік Новий!
Ми тебе весело зустрінем,
Ми тебе весело зустрінем -
Малюки!
І тобі пісню заспіваєм,
І тобі пісню заспіваєм
Залюбки!

