INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_238716','Що на Петра Хліб пекла а на Йвана вибирала','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','А на Йвана вибирала — що, кого вибирала? Пара - любощі: Купання. Піч-Хліб. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Обрядове Купання. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. Що на Петра Хліб пекла а на Йвана вибирала. Були Світилки Яснії Зірки. Листки з приводу цієї Пісні: Українські релігійні роздуми про Бога. Про Свято Івана Купала Стежки до листків про Українські традиції.','Що на Петра Хліб пекла
А на Йвана вибирала
Купало на Йвана!

Де ж ти купався
Води не боявся
Купало на Йвана!    Голос 3','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_238716'), datetime('now')),datetime('now'));
