INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2389495','Цей день для друзів','Музика: Сергій Шишкін Слова: Сергій Шишкін. Виконує: Сергій Шишкін','uk','ukraine_1991',NULL,'2019','Літопис авторської пісні України №39 (577) 2019 рік.',NULL,'День такий,
Що для спогадів час
Це все про нас.
День такий -
Перегорнутий вітром сонним,
День сторонний,
Не легкий,
Не помічений вкотре і не раз
День такий,
Що залишиться в тій безодні...

Приспів:
Для друзів!..       |
Цей день для друзів |
У крузі,            |
В тісному крузі!    | (2)

День такий,
Не останній і не судній...
День такий,
Що не кінчиться ніяк...
Та під вечір
Вже не будеш у напрузі...
День такий,
Врешті скінчились всі козні...

Приспів.

Речитатив:
Забуваєш проблеми,
Про всі незгоди, коли разом!
І кращі спогади - всі теми,
Разом ми робимо погоду.
Сам чорт - не брат, коли разом!','[''pisni.org.ua'', ''cat:druzhba'', ''Пісні про дружбу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2389495'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2389495','Цей день для друзів','День такий,
