INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_238919','Поскакав Коник попід Гречкою','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Пара - любощі: Кінь-Гречка. Вода. Сватання. Вибір Пари. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. Постій Конику я загнуздаю. Ой біжит Коник під Гречкою Ой що то іде Селом Cелом Поскакав Коник попід Гречкою Хтось у Борі гукає Були Світилки Яснії Зірки. Прийшли Сватуни мене сватати. Листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Українські релігійні роздуми про Бога. Про Свято Івана Купала Стежки до листків про Українські традиції.','Поскакав Коник попід Гречкою
А за ним за ним я з Уздечкою  |(2)

Постій Конику я загнуздаю
Поведу Тебе аж до Дунаю |(2)

Аж до Дунаю Водиці пити
До Терпилових Дівку сватати |(2)

А в Терпилових злії собаки
Не допускають Сватів до Хати  |(2)

Вийшла Маруся обороняти
Пошли Собаки в Солому спати  |(2)

Пошли Собаки в Солому спати
Прийшли Сватуни мене сватати!  |(2)','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_238919'), datetime('now')),datetime('now'));
