INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2395175','Бабусина вишиванка','Музика: Сергій Родько Слова: Алла Бінцаровська','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконують Надійка та Софійка Стельмахи.','Вечорами довгими не спала,
А бувало, навіть до зорі,
Трепетно бабуся вишивала
Хрестики на білім полотні.
Зацвіли фіалочки барвисті
І троянди ніжні пелюстки,
Щоб онучці вроду чисту-чисту
Принесли бабусині рядки!

Приспів:
Бабусина вишиванка -
Дарунок на все життя,
Щоб квітли мої світанки
Мережкою вишиття.
Нехай кольори веснянки
Мене бережуть від бід,
Бабусина вишиванка,
Мов долі моєї цвіт!

Ця сорочка, наче берегиня,
Моїх перших мрій і сподівань!
Я пишаюсь нею у родині,
Радо одягаю без вагань!
Хай твої, бабусю, щедрі руки
Бог благословляє кожен день,
Щоб росли щасливими онуки
І співали сонячних пісень!

Приспів. (2)','[''pisni.org.ua'', ''cat:dytyachi'', ''cat:pro-batkiv'', ''cat:pro-ditey'', ''Дитячі пісні'', ''Пісні про любов до батьків'', ''Пісні про любов до дітей'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2395175'), datetime('now')),datetime('now'));
